mapper.select:
SELECT COUNT(*) 
FROM recipe 
WHERE member_id = #{memberId}

SELECT COUNT(DISTINCT r.recipe_id) FROM recipe r LEFT OUTER JOIN review r2 ON r.recipe_id = r2.recipe_id
r.recipe_id IN ( SELECT recipe_id FROM recipe_category WHERE category_id IN
#{cat}
)

SELECT * FROM ( SELECT ROWNUM AS rn, recipe_id AS recipeId, member_id AS member_Id, title, description, serving_size AS servingSize, main_image AS mainImage, created_at, difficulty, cooking_time AS cookingTime, hit, rating FROM ( SELECT r.recipe_id, r.member_id, r.title, r.description, r.serving_size, TO_CHAR(r.main_image) AS main_image, r.created_at, r.difficulty, r.cooking_time, r.hit, NVL(AVG(r2.rating), 0) AS rating FROM recipe r LEFT OUTER JOIN review r2 ON r.recipe_id = r2.recipe_id
r.recipe_id IN ( SELECT recipe_id FROM recipe_category WHERE category_id IN
#{cat}
)
GROUP BY r.recipe_id, r.member_id, r.title, r.description, r.serving_size, TO_CHAR(r.main_image), r.created_at, r.difficulty, r.cooking_time, r.hit
ORDER BY rating DESC, r.recipe_id ASC
ORDER BY r.created_at DESC, r.recipe_id ASC
ORDER BY r.hit DESC, r.recipe_id ASC
) ) WHERE rn BETWEEN #{startRow} AND #{endRow}
